import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ReferencesService } from "src/app/core/services/references.service";
import { BranchPeriod } from '../../Models/Settings/BranchReference';
import { DatePipe } from "@angular/common";
import { format } from 'date-fns';
import { HttpClient } from '@angular/common/http';
import { EnvService } from 'src/app/core/services/env.service';
import { AlertService } from 'src/app/core/services/alert.service';
@Component({
  selector: 'app-end-of-period',
  templateUrl: './end-of-period.page.html',
  styleUrls: ['./end-of-period.page.scss'],
})
export class EndOfPeriodPage implements OnInit {
  showLoader: boolean = false;
  disabled: boolean = false;
  GetBranchPeriod: BranchPeriod;

  constructor(
    private formBuilder: FormBuilder,
    private ReferencesService: ReferencesService,
    private http: HttpClient,
    private env: EnvService,
    private alertServices: AlertService,
  ) { }
  BranchForm: FormGroup = this.formBuilder.group({
    period_start_date: [""],
    period_end_date: [""],
  })
  async ngOnInit() {

    this.GetBranchPeriod = await this.ReferencesService.GetBranchPeriod();
  }

  DateFormatStyle = (input: string):string=> {
    return format(new Date(input), "yyyy-MM-dd")
  }
  End(){
    this.showLoader = true;
    this.http
      .post(this.env.API_URL + "api/Settings/GetEndOfPeriod", {
        period_start_date: this.GetBranchPeriod.period_start_date.toString(),
        period_end_date: this.GetBranchPeriod.period_end_date.toString(),
      })
      .subscribe({
        next: (data) => {
          this.showLoader = false;
          this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
        },
        error: (err) => {
          console.log(err);
          this.alertServices.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
  } 


}
